import{_ as a,o as e,c as p,a2 as i}from"./chunks/framework.Crpw6aS5.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"2 计算机/开发框架/ROS2/Generic Publishers 实现方案.md","filePath":"2 计算机/开发框架/ROS2/Generic Publishers 实现方案.md","lastUpdated":1776232971000}'),n={name:"2 计算机/开发框架/ROS2/Generic Publishers 实现方案.md"};function l(r,s,t,c,h,d){return e(),p("div",null,[...s[0]||(s[0]=[i(`<p>Generic Publishers 的实现核心思想是：<strong>绕过编译时类型检查，通过运行时动态加载和序列化来实现类型无关的发布</strong>。具体机制如下：</p> <h2 id="核心架构" tabindex="-1">核心架构 <a class="header-anchor" href="#核心架构" aria-label="Permalink to &quot;核心架构&quot;">​</a></h2> <h3 id="_1-非模板类设计" tabindex="-1">1. 非模板类设计 <a class="header-anchor" href="#_1-非模板类设计" aria-label="Permalink to &quot;1. 非模板类设计&quot;">​</a></h3> <p><a href="./rclcpp/include/rclcpp/generic_publisher.hpp.html#L28-L57">GenericPublisher</a> 不是模板类，直接继承自 <code>PublisherBase</code>。因为编译时不知道类型，所以无法使用模板参数化。</p> <p>关键成员：</p> <div class="language-cpp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">std</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::shared_ptr</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rcpputils</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::SharedLibrary</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ts_lib_;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 持有类型支持库，确保不被卸载</span></span></code></pre> <div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_2-运行时类型支持加载" tabindex="-1">2. 运行时类型支持加载 <a class="header-anchor" href="#_2-运行时类型支持加载" aria-label="Permalink to &quot;2. 运行时类型支持加载&quot;">​</a></h3> <p>通过 <a href="./rclcpp/include/rclcpp/typesupport_helpers.hpp.html#L48-L93">typesupport_helpers</a> 实现：</p> <p><strong>步骤1：解析类型字符串</strong></p> <ul><li><a href="./rclcpp/src/rclcpp/typesupport_helpers.cpp.html#L69-L92">extract_type_identifier()</a> 从 <code>&quot;std_msgs/msg/String&quot;</code> 中提取出 <code>(package_name=&quot;std_msgs&quot;, middle_module=&quot;msg&quot;, type_name=&quot;String&quot;)</code></li></ul> <p><strong>步骤2：定位并加载类型支持库</strong></p> <ul><li><a href="./rclcpp/src/rclcpp/typesupport_helpers.cpp.html#L94-L111">get_typesupport_library_path()</a> 在 ament 索引中查找库路径，如 <code>libstd_msgs__rosidl_typesupport_cpp.so</code></li> <li><a href="./rclcpp/src/rclcpp/typesupport_helpers.cpp.html#L113-L117">get_typesupport_library()</a> 使用 <code>rcpputils::SharedLibrary</code> 动态加载</li></ul> <p><strong>步骤3：获取类型支持句柄</strong></p> <ul><li><a href="./rclcpp/src/rclcpp/typesupport_helpers.cpp.html#L119-L131">get_message_typesupport_handle()</a> 通过符号查找获取类型支持句柄</li> <li>符号命名规则：<code>{typesupport_identifier}__get_message_type_support_handle__{package_name}__{middle_module}__{type_name}</code></li></ul> <h3 id="_3-序列化消息传递" tabindex="-1">3. 序列化消息传递 <a class="header-anchor" href="#_3-序列化消息传递" aria-label="Permalink to &quot;3. 序列化消息传递&quot;">​</a></h3> <p><a href="./rclcpp/src/rclcpp/generic_publisher.cpp.html#L13-L22">GenericPublisher::publish()</a> 直接发布序列化消息：</p> <div class="language-cpp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rcl_publish_serialized_message</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_publisher_handle</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">().</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(), </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">message.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_rcl_serialized_message</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">NULL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre> <div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><a href="./rclcpp/include/rclcpp/serialized_message.hpp.html#L25-L35">SerializedMessage</a> 封装了 <code>rcl_serialized_message_t</code>，提供 RAII 语义管理二进制数据。</p> <h3 id="_4-零拷贝优化-可选" tabindex="-1">4. 零拷贝优化（可选） <a class="header-anchor" href="#_4-零拷贝优化-可选" aria-label="Permalink to &quot;4. 零拷贝优化（可选）&quot;">​</a></h3> <p><a href="./rclcpp/src/rclcpp/generic_publisher.cpp.html#L24-L27">publish_as_loaned_msg()</a> 提供了借出消息机制：</p> <ol><li><a href="./rclcpp/src/rclcpp/generic_publisher.cpp.html#L29-L43">borrow_loaned_message()</a>：从中间件借用消息内存</li> <li><a href="./rclcpp/src/rclcpp/generic_publisher.cpp.html#L45-L51">deserialize_message()</a>：将序列化数据反序列化到借出的内存</li> <li><a href="./rclcpp/src/rclcpp/generic_publisher.cpp.html#L53-L60">publish_loaned_message()</a>：直接发布借出的消息，避免拷贝</li></ol> <h2 id="工作流程" tabindex="-1">工作流程 <a class="header-anchor" href="#工作流程" aria-label="Permalink to &quot;工作流程&quot;">​</a></h2> <div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户指定类型字符串 (如 &quot;std_msgs/msg/String&quot;)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>extract_type_identifier() 解析出 package/msg/type</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>get_typesupport_library_path() 找到 .so 文件路径</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>SharedLibrary 动态加载库</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>get_message_typesupport_handle() 通过符号查找获取类型句柄</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>GenericPublisher 构造时使用类型句柄初始化 PublisherBase</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>publish() 时直接发送 SerializedMessage 二进制数据</span></span></code></pre> <div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><h2 id="限制" tabindex="-1">限制 <a class="header-anchor" href="#限制" aria-label="Permalink to &quot;限制&quot;">​</a></h2> <ul><li><strong>不支持进程内通信</strong>：文档明确说明不支持 intra-process handling，因为类型在编译时未知</li> <li><strong>性能开销</strong>：动态加载库和序列化/反序列化都有额外成本</li> <li><strong>类型安全缺失</strong>：编译器无法检查类型匹配，错误只能在运行时发现</li></ul> <p>这个设计巧妙地利用了 ROS 2 的类型支持系统，通过动态链接库和序列化机制，实现了编译时类型未知的情况下的消息发布。</p>`,48)])])}const _=a(n,[["render",l]]);export{u as __pageData,_ as default};
